const DOC_TYPES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  'application/vnd.ms-excel',
  'text/csv',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/msword',
];
const MIN_IMAGE_KB = 40; // signatures/logos are below this; covers/flyers above

function sizeKB(b) {
  const m = (b.fileSize || '').toString().match(/([\d.]+)\s*(kB|MB|B)\b/i);
  if (!m) return Infinity;
  const n = parseFloat(m[1]);
  const u = m[2].toUpperCase();
  return u === 'MB' ? n * 1024 : u === 'B' ? n / 1024 : n;
}

const out = [];
for (const item of $input.all()) {
  const bin = item.binary || {};
  for (const key of Object.keys(bin)) {
    const b = bin[key];
    const mime = (b.mimeType || '').toLowerCase();
    const isImage = mime.startsWith('image/');

    if (isImage && sizeKB(b) < MIN_IMAGE_KB) continue;   // drop only small images (signatures)
    if (!DOC_TYPES.includes(mime) && !isImage) continue; // ignore non-doc, non-image files

    out.push({
      json: { message_id: item.json.id, thread_id: item.json.threadId, filename: b.fileName || key },
      binary: { data: b },
    });
  }
}
return out;

// Group parsed markdown per email into a single attachments_text string.
const byEmail = {};
for (const item of $input.all()) {
  const id = item.json.message_id;
  const md = item.json.attachment_markdown || '';
  if (!byEmail[id]) byEmail[id] = [];
  if (md) byEmail[id].push(md);
}
return Object.keys(byEmail).map((id) => ({
  json: { message_id: id, attachments_text: byEmail[id].join('\n\n---\n\n') },
}));

// Explode each relevant AI result into one row per catalog item, mapped to the REAL
// catalog_lines columns. Derives the shortened CODE from the EAN. Extras -> extra (jsonb).
function toCatalogCode(ean) {
  if (ean === null || ean === undefined) return null;
  const s = String(ean).replace(/\D/g, '');
  if (!s) return null;
  const trimmed = s.slice(0, -1).replace(/^0+/, '');
  return trimmed || null;
}

const rows = [];
const inputs = $input.all();
for (let i = 0; i < inputs.length; i++) {
  let result = inputs[i].json;
  result = result.message?.content ?? result.content ?? result;
  if (typeof result === 'string') { try { result = JSON.parse(result); } catch (e) { continue; } }
  if (!result || result.is_catalog_relevant === false) continue;

  let src = {};
  try { src = $('Set Fields').itemMatching(i).json; } catch (e) {}

  for (const item of (result.items ?? [])) {
    rows.push({ json: {
      action: item.action === 'update' ? 'update' : 'create',   // routing only (ignored on write)
      match_line_id: item.match_line_id ?? null,                // routing only (ignored on write)

      status: item.excluded ? 'excluded' : 'in_progress',
      label: result.label ?? null,
      thread_id: src.thread_id ?? null,
      artist: item.artist ?? null,
      title: item.title ?? null,
      format: item.format ?? null,
      genre: item.genre ?? null,
      unit: item.unit ?? null,
      ean: item.ean ?? null,
      code: toCatalogCode(item.ean),
      catalogue_no: item.catalogue_no ?? null,
      release_date: item.release_date ?? null,
      price_original: item.price ?? null,
      currency: item.currency ?? null,
      cop: item.cop ?? null,
      ppd: (function(a,b){a=a!=null?String(a).replace('.',','):null;b=b!=null?String(b).replace('.',','):null;return a&&b?a+'/'+b:(a||b||null);})(item.ppd_eur, item.rock_bottom),
      rock_bottom: item.rock_bottom ?? null,
      our_price: null,
      calculation_group: item.calculation_group ?? null,
      supplier_code: item.supplier_code ?? null,
      missing_fields: item.missing_mandatory ?? [],
      confidence: item.item_confidence ?? result.overall_confidence ?? null,
      notes: item.item_notes ?? null,
      extra: {
        artist_raw: item.artist_raw ?? null,
        exclusion_reason: item.exclusion_reason ?? null,
        match_confidence: item.match_confidence ?? null,
        needs_review: result.needs_review ?? null,
        source_message_id: src.message_id ?? null,
      },
    } });
  }
}
return rows;

